def _parse_gs_uri(uri: str) -> Tuple[str, str]:
    if not uri.startswith("gs://"):
        raise ValueError(f"Not a gs:// URI: {uri}")
    path = uri[5:]
    parts = path.split("/", 1)
    bucket = parts[0]
    name = parts[1] if len(parts) > 1 else ""
    return bucket, name


def _safe_filename(name: str) -> str:
    name = os.path.basename(name or "")
    name = re.sub(r"[^A-Za-z0-9._-]+", "_", name).strip("._")
    return name or "file"


def _get_metadata(event: Dict[str, Any]) -> Dict[str, str]:
    md = event.get("metadata") or {}
    if not isinstance(md, dict):
        md = {}
    out = {}
    for k, v in md.items():
        if v is None:
            continue
        out[str(k)] = str(v)
    return out


def _split_args(s: str) -> List[str]:
    if not s:
        return []
    s = urllib.parse.unquote_plus(s)
    return shlex.split(s)


def _derive_output_name(input_name: str, fmt: str, suffix: str = "") -> str:
    base = os.path.basename(input_name)
    root, _ext = os.path.splitext(base)
    if suffix:
        root = f"{root}{suffix}"
    fmt = (fmt or "").lstrip(".").lower() or "jpg"
    return f"{root}.{fmt}"


def _download_blob(client: storage.Client, bucket: str, name: str, local_path: str) -> None:
    b = client.bucket(bucket)
    blob = b.blob(name)
    blob.download_to_filename(local_path)


def _upload_blob(
    client: storage.Client,
    bucket: str,
    name: str,
    local_path: str,
    content_type: str = None,
    metadata: Dict[str, str] = None,
) -> None:
    b = client.bucket(bucket)
    blob = b.blob(name)
    if content_type:
        blob.content_type = content_type
    if metadata:
        blob.metadata = metadata
    blob.upload_from_filename(local_path)


def _is_convertable_image(content_type: str, name: str) -> bool:
    if content_type and content_type.startswith("image/"):
        return True
    ext = os.path.splitext(name or "")[1].lower()
    return ext in {".jpg", ".jpeg", ".png", ".gif", ".tif", ".tiff", ".bmp", ".webp", ".heic", ".heif"}


